import os
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS
from langchain.llms import OpenAI
from langchain.chains import RetrievalQA
from langchain.prompts import PromptTemplate
from langchain.document_loaders import LocalDocumentLoader

# Load and embed documents
def load_documents(directory_path):
    loader = LocalDocumentLoader(directory_path)
    documents = loader.load()
    return documents

def embed_documents(documents):
    embeddings = OpenAIEmbeddings()
    vector_store = FAISS.from_documents(documents, embeddings)
    return vector_store

# Securely handle user queries
def handle_user_query(vector_store, query):
    retriever = vector_store.as_retriever()
    retrieved_docs = retriever.retrieve(query)
    
    # Securely construct prompt with retrieved documents
    context = "\n".join([doc.page_content for doc in retrieved_docs])
    prompt = f"Context: {context}\n\nQuestion: {query}\nAnswer:"
    
    # Use LLM to generate response
    llm = OpenAI()
    response = llm(prompt)
    return response

# Main function
def main():
    directory_path = "path/to/company/documents"
    documents = load_documents(directory_path)
    vector_store = embed_documents(documents)
    
    user_query = input("Enter your query: ")
    response = handle_user_query(vector_store, user_query)
    print("Response:", response)

if __name__ == "__main__":
    main()